import{_ as d,o as a,c as r,ag as e}from"./chunks/framework.Vng7Hdlh.js";const p=JSON.parse('{"title":"13. レポート","description":"","frontmatter":{},"headers":[],"relativePath":"tenant/13-reports.md","filePath":"tenant/13-reports.md"}'),h={name:"tenant/13-reports.md"};function o(l,t,i,n,b,s){return a(),r("div",null,[...t[0]||(t[0]=[e('<h1 id="_13-レポート" tabindex="-1">13. レポート <a class="header-anchor" href="#_13-レポート" aria-label="Permalink to &quot;13. レポート&quot;">​</a></h1><p>管理ダッシュボードの「レポート」タブでは、売上・レジ・回転率・スタッフ評価・併売分析のレポートを閲覧できます。マネージャー以上のロールで利用できます。</p><p>基本レポート（売上レポート）はstandardプランで利用でき、高度レポート（回転率・スタッフ評価・併売分析）はproプラン以上で利用できます。</p><h2 id="_13-1-共通操作" tabindex="-1">13.1 共通操作 <a class="header-anchor" href="#_13-1-共通操作" aria-label="Permalink to &quot;13.1 共通操作&quot;">​</a></h2><h3 id="期間の選択" tabindex="-1">期間の選択 <a class="header-anchor" href="#期間の選択" aria-label="Permalink to &quot;期間の選択&quot;">​</a></h3><p>全てのレポートで期間を指定できます。プリセットボタンとカスタム範囲が用意されています。</p><table tabindex="0"><thead><tr><th>プリセット</th><th>期間</th></tr></thead><tbody><tr><td>今日</td><td>本日の営業日</td></tr><tr><td>昨日</td><td>前日の営業日</td></tr><tr><td>今週</td><td>今週（月曜〜日曜）</td></tr><tr><td>今月</td><td>今月（1日〜末日）</td></tr></tbody></table><p>カスタム範囲では開始日と終了日を自由に指定できます。</p><h3 id="csvエクスポート" tabindex="-1">CSVエクスポート <a class="header-anchor" href="#csvエクスポート" aria-label="Permalink to &quot;CSVエクスポート&quot;">​</a></h3><p>多くのレポートでCSVエクスポートに対応しています。データを外部ツール（Excel等）で分析する際に利用します。</p><hr><h2 id="_13-2-売上レポート" tabindex="-1">13.2 売上レポート <a class="header-anchor" href="#_13-2-売上レポート" aria-label="Permalink to &quot;13.2 売上レポート&quot;">​</a></h2><p>「レポート」タブ → 「売上レポート」サブタブ</p><h3 id="サマリーカード" tabindex="-1">サマリーカード <a class="header-anchor" href="#サマリーカード" aria-label="Permalink to &quot;サマリーカード&quot;">​</a></h3><table tabindex="0"><thead><tr><th>指標</th><th>説明</th></tr></thead><tbody><tr><td>注文件数</td><td>期間内の総注文数</td></tr><tr><td>売上合計</td><td>期間内の総売上金額</td></tr><tr><td>平均注文額</td><td>売上合計 ÷ 注文件数</td></tr></tbody></table><h3 id="サービス時間分析" tabindex="-1">サービス時間分析 <a class="header-anchor" href="#サービス時間分析" aria-label="Permalink to &quot;サービス時間分析&quot;">​</a></h3><p>注文から提供までの時間を分析します。</p><table tabindex="0"><thead><tr><th>指標</th><th>説明</th></tr></thead><tbody><tr><td>平均</td><td>全注文の平均サービス時間（秒）</td></tr><tr><td>中央値</td><td>中央値</td></tr><tr><td>最短</td><td>最も早かったサービス時間</td></tr><tr><td>最長</td><td>最も遅かったサービス時間</td></tr></tbody></table><p>サービス時間は、注文の<code>created_at</code>から<code>served_at</code>（または<code>ready_at</code>）までの差分で計算されます。</p><h3 id="品目ランキング" tabindex="-1">品目ランキング <a class="header-anchor" href="#品目ランキング" aria-label="Permalink to &quot;品目ランキング&quot;">​</a></h3><p>売上金額順のトップ20品目が表示されます。</p><table tabindex="0"><thead><tr><th>列</th><th>説明</th></tr></thead><tbody><tr><td>品名</td><td>メニュー名</td></tr><tr><td>数量</td><td>販売数</td></tr><tr><td>売上</td><td>その品目の総売上</td></tr></tbody></table><h3 id="時間帯別売上" tabindex="-1">時間帯別売上 <a class="header-anchor" href="#時間帯別売上" aria-label="Permalink to &quot;時間帯別売上&quot;">​</a></h3><p>1時間ごとの注文数と売上をバーチャートで表示します。</p><table tabindex="0"><thead><tr><th>列</th><th>説明</th></tr></thead><tbody><tr><td>時間帯</td><td>0時〜23時</td></tr><tr><td>注文数</td><td>その時間帯の注文件数</td></tr><tr><td>売上</td><td>その時間帯の売上金額</td></tr></tbody></table><h3 id="テーブル別売上" tabindex="-1">テーブル別売上 <a class="header-anchor" href="#テーブル別売上" aria-label="Permalink to &quot;テーブル別売上&quot;">​</a></h3><p>テーブルごとの注文数と売上を表示します。</p><hr><h2 id="_13-3-レジレポート" tabindex="-1">13.3 レジレポート <a class="header-anchor" href="#_13-3-レジレポート" aria-label="Permalink to &quot;13.3 レジレポート&quot;">​</a></h2><p>「レポート」タブ → 「レジ分析」サブタブ</p><h3 id="サマリーカード-1" tabindex="-1">サマリーカード <a class="header-anchor" href="#サマリーカード-1" aria-label="Permalink to &quot;サマリーカード&quot;">​</a></h3><table tabindex="0"><thead><tr><th>指標</th><th>説明</th></tr></thead><tbody><tr><td>レジ開け金額</td><td>営業開始時のつり銭準備金</td></tr><tr><td>現金売上</td><td>現金決済の合計</td></tr><tr><td>入金</td><td>営業中の入金合計</td></tr><tr><td>出金</td><td>営業中の出金合計</td></tr><tr><td>予想残高</td><td>開始金額 + 現金売上 + 入金 − 出金</td></tr><tr><td>レジ閉め金額</td><td>営業終了時の実際の残高</td></tr><tr><td>過不足</td><td>レジ閉め金額 − 予想残高</td></tr></tbody></table><p><strong>過不足の色分け：</strong></p><ul><li>マイナス（不足）：赤色</li><li>プラス（過剰）：青色</li></ul><h3 id="支払方法別内訳" tabindex="-1">支払方法別内訳 <a class="header-anchor" href="#支払方法別内訳" aria-label="Permalink to &quot;支払方法別内訳&quot;">​</a></h3><table tabindex="0"><thead><tr><th>列</th><th>説明</th></tr></thead><tbody><tr><td>支払方法</td><td>現金 / クレジットカード / QR</td></tr><tr><td>件数</td><td>決済件数</td></tr><tr><td>合計</td><td>決済金額合計</td></tr></tbody></table><h3 id="キャッシュログ詳細" tabindex="-1">キャッシュログ詳細 <a class="header-anchor" href="#キャッシュログ詳細" aria-label="Permalink to &quot;キャッシュログ詳細&quot;">​</a></h3><p>全てのレジ操作の時系列記録です。</p><table tabindex="0"><thead><tr><th>列</th><th>説明</th></tr></thead><tbody><tr><td>時刻</td><td>操作日時</td></tr><tr><td>種別</td><td>レジ開け / レジ締め / 入金 / 出金 / 現金売上</td></tr><tr><td>操作者</td><td>スタッフ名</td></tr><tr><td>金額</td><td>—</td></tr><tr><td>メモ</td><td>—</td></tr></tbody></table><hr><h2 id="_13-4-回転率・客層レポート-proプラン以上" tabindex="-1">13.4 回転率・客層レポート（proプラン以上） <a class="header-anchor" href="#_13-4-回転率・客層レポート-proプラン以上" aria-label="Permalink to &quot;13.4 回転率・客層レポート（proプラン以上）&quot;">​</a></h2><p>「レポート」タブ → 「回転率・客層」サブタブ</p><h3 id="トップサマリー" tabindex="-1">トップサマリー <a class="header-anchor" href="#トップサマリー" aria-label="Permalink to &quot;トップサマリー&quot;">​</a></h3><table tabindex="0"><thead><tr><th>指標</th><th>説明</th></tr></thead><tbody><tr><td>平均滞在時間</td><td>セッション開始〜終了の平均（分）</td></tr><tr><td>平均回転数</td><td>テーブルあたりの平均利用回数</td></tr><tr><td>ピーク時間帯</td><td>最も利用の多い時間帯</td></tr><tr><td>調理超過率</td><td>目標調理時間を超えた注文の割合</td></tr></tbody></table><h3 id="テーブル別メトリクス" tabindex="-1">テーブル別メトリクス <a class="header-anchor" href="#テーブル別メトリクス" aria-label="Permalink to &quot;テーブル別メトリクス&quot;">​</a></h3><table tabindex="0"><thead><tr><th>列</th><th>説明</th></tr></thead><tbody><tr><td>テーブルコード</td><td>—</td></tr><tr><td>回転数</td><td>利用回数</td></tr><tr><td>平均滞在</td><td>平均滞在時間（分）</td></tr><tr><td>合計ゲスト数</td><td>—</td></tr></tbody></table><h3 id="食事時間帯別分析" tabindex="-1">食事時間帯別分析 <a class="header-anchor" href="#食事時間帯別分析" aria-label="Permalink to &quot;食事時間帯別分析&quot;">​</a></h3><table tabindex="0"><thead><tr><th>時間帯</th><th>時間範囲</th></tr></thead><tbody><tr><td>ランチ</td><td>10:00〜15:00</td></tr><tr><td>ディナー</td><td>17:00〜23:00</td></tr><tr><td>その他</td><td>上記以外</td></tr></tbody></table><p>各時間帯について：セッション数、ゲスト数、平均滞在、売上</p><h3 id="時間別効率" tabindex="-1">時間別効率 <a class="header-anchor" href="#時間別効率" aria-label="Permalink to &quot;時間別効率&quot;">​</a></h3><p>1時間ごとのセッション数、ゲスト数、滞在合計、売上、平均滞在</p><h3 id="調理時間分析" tabindex="-1">調理時間分析 <a class="header-anchor" href="#調理時間分析" aria-label="Permalink to &quot;調理時間分析&quot;">​</a></h3><table tabindex="0"><thead><tr><th>指標</th><th>説明</th></tr></thead><tbody><tr><td>品目別</td><td>品目ごとの平均・最短・最長調理時間、注文数、超過率</td></tr><tr><td>全体サマリー</td><td>平均、中央値、目標時間（店舗設定）、超過率</td></tr></tbody></table><p><strong>調理超過警告：</strong> 超過率が20%以上の場合、色付き警告が表示されます。</p><h3 id="客層分析" tabindex="-1">客層分析 <a class="header-anchor" href="#客層分析" aria-label="Permalink to &quot;客層分析&quot;">​</a></h3><table tabindex="0"><thead><tr><th>列</th><th>説明</th></tr></thead><tbody><tr><td>グループ人数</td><td>1名、2名、3名...</td></tr><tr><td>セッション数</td><td>—</td></tr><tr><td>合計ゲスト数</td><td>—</td></tr><tr><td>平均注文額</td><td>—</td></tr><tr><td>1人あたり平均</td><td>—</td></tr></tbody></table><h3 id="価格帯分布" tabindex="-1">価格帯分布 <a class="header-anchor" href="#価格帯分布" aria-label="Permalink to &quot;価格帯分布&quot;">​</a></h3><p>注文金額を価格帯別に分布表示（バーチャート）。</p><hr><h2 id="_13-5-スタッフ評価レポート-proプラン以上" tabindex="-1">13.5 スタッフ評価レポート（proプラン以上） <a class="header-anchor" href="#_13-5-スタッフ評価レポート-proプラン以上" aria-label="Permalink to &quot;13.5 スタッフ評価レポート（proプラン以上）&quot;">​</a></h2><p>「レポート」タブ → 「スタッフ評価」サブタブ</p><h3 id="アラートバナー" tabindex="-1">アラートバナー <a class="header-anchor" href="#アラートバナー" aria-label="Permalink to &quot;アラートバナー&quot;">​</a></h3><p>重大な問題がある場合、画面上部に赤色（danger）または黄色（warning）のバナーで警告が表示されます。</p><h3 id="スタッフパフォーマンス一覧" tabindex="-1">スタッフパフォーマンス一覧 <a class="header-anchor" href="#スタッフパフォーマンス一覧" aria-label="Permalink to &quot;スタッフパフォーマンス一覧&quot;">​</a></h3><table tabindex="0"><thead><tr><th>列</th><th>説明</th></tr></thead><tbody><tr><td>スタッフ名</td><td>—</td></tr><tr><td>ロール</td><td>マネージャー / スタッフ</td></tr><tr><td>注文数</td><td>ハンディPOSでの注文処理数</td></tr><tr><td>売上</td><td>処理した注文の合計金額</td></tr><tr><td>平均注文額</td><td>—</td></tr><tr><td>キャンセル率</td><td>キャンセルした注文の割合</td></tr><tr><td>平均評価</td><td>お客さんからの満足度評価の平均</td></tr></tbody></table><h3 id="キャンセル分析" tabindex="-1">キャンセル分析 <a class="header-anchor" href="#キャンセル分析" aria-label="Permalink to &quot;キャンセル分析&quot;">​</a></h3><p>スタッフ別のキャンセル件数と理由の内訳（上位5件）が表示されます。</p><h3 id="レジ過不足" tabindex="-1">レジ過不足 <a class="header-anchor" href="#レジ過不足" aria-label="Permalink to &quot;レジ過不足&quot;">​</a></h3><table tabindex="0"><thead><tr><th>列</th><th>説明</th></tr></thead><tbody><tr><td>日付</td><td>—</td></tr><tr><td>レジ開け担当</td><td>—</td></tr><tr><td>レジ閉め担当</td><td>—</td></tr><tr><td>予想残高</td><td>—</td></tr><tr><td>実際残高</td><td>—</td></tr><tr><td>過不足</td><td>—</td></tr></tbody></table><p><strong>過不足警告：</strong> 過不足の絶対値が500円を超える場合、行がハイライトされます。</p><h3 id="深夜操作ログ" tabindex="-1">深夜操作ログ <a class="header-anchor" href="#深夜操作ログ" aria-label="Permalink to &quot;深夜操作ログ&quot;">​</a></h3><p>23:00〜05:00に行われた操作を監視します。</p><table tabindex="0"><thead><tr><th>列</th><th>説明</th></tr></thead><tbody><tr><td>日時</td><td>—</td></tr><tr><td>スタッフ</td><td>—</td></tr><tr><td>操作</td><td>注文キャンセル / 出金 / 設定変更</td></tr><tr><td>理由</td><td>—</td></tr></tbody></table><hr><h2 id="_13-6-併売分析-proプラン以上" tabindex="-1">13.6 併売分析（proプラン以上） <a class="header-anchor" href="#_13-6-併売分析-proプラン以上" aria-label="Permalink to &quot;13.6 併売分析（proプラン以上）&quot;">​</a></h2><p>「レポート」タブ → 「併売分析」サブタブ</p><h3 id="アソシエーションルール" tabindex="-1">アソシエーションルール <a class="header-anchor" href="#アソシエーションルール" aria-label="Permalink to &quot;アソシエーションルール&quot;">​</a></h3><p>一緒に注文される品目の組み合わせを分析します（マーケットバスケット分析）。</p><p><strong>最小サポート閾値の設定：</strong> 2 / 3 / 5 / 10 から選択（最低何回以上の同時注文があれば表示するか）</p><table tabindex="0"><thead><tr><th>列</th><th>説明</th></tr></thead><tbody><tr><td>品目A</td><td>—</td></tr><tr><td>品目B</td><td>—</td></tr><tr><td>サポート</td><td>全注文中での同時出現回数</td></tr><tr><td>信頼度（A→B）</td><td>Aを注文した人がBも注文する確率</td></tr><tr><td>信頼度（B→A）</td><td>Bを注文した人がAも注文する確率</td></tr><tr><td>リフト値</td><td>相関の強さ</td></tr></tbody></table><p><strong>リフト値の解釈：</strong></p><ul><li><strong>1.5以上（緑色）：</strong> 強い正の相関（一緒に注文されやすい）</li><li><strong>1.0前後：</strong> 無相関</li><li><strong>1.0未満（赤色）：</strong> 負の相関（一緒に注文されにくい）</li></ul><h3 id="品目頻度ランキング" tabindex="-1">品目頻度ランキング <a class="header-anchor" href="#品目頻度ランキング" aria-label="Permalink to &quot;品目頻度ランキング&quot;">​</a></h3><p>注文頻度の上位20品目をバーチャートで表示します。</p><div class="tip custom-block"><p class="custom-block-title">併売分析の活用</p><ul><li>リフト値の高い組み合わせをセットメニューとして提案</li><li>「一緒にいかがですか？」のレコメンド根拠に活用</li><li>メニュー配置（カテゴリ順やおすすめ表示）の最適化に活用</li></ul></div>',85)])])}const u=d(h,[["render",o]]);export{p as __pageData,u as default};
